INSERT INTO `post` VALUES (1,2,'如何撰写一份优秀的商业计划书？','撰写商业计划书是创业的重要步骤，需要包含市场分析、商业模式、财务规划等内容。大家有什么好的建议吗？','question','创业指导','商业计划,融资',120,15,8,1,NULL,'2026-04-04 21:03:00','2026-04-04 21:03:00',0),(2,3,'2026年最值得投资的创业方向','根据市场趋势，人工智能、清洁能源、健康科技等领域具有巨大潜力。大家怎么看？','article','投资分析','投资趋势,创业方向',200,26,12,1,NULL,'2026-04-04 21:03:00','2026-04-04 21:03:00',0),(3,4,'技术咨询服务的重要性','专业的技术咨询可以帮助初创企业避免许多技术陷阱，加速产品开发。','article','技术服务','技术咨询,创业支持',81,8,5,1,NULL,'2026-04-04 21:03:00','2026-04-04 21:03:00',0),(4,2,'寻找技术合伙人的经验分享','我在寻找技术合伙人的过程中遇到了很多挑战，最终找到了合适的伙伴。分享一些经验...','article','团队建设','合伙人,团队',150,20,10,1,NULL,'2026-04-04 21:03:00','2026-04-04 21:03:00',0),(5,3,'早期项目评估的关键因素','作为投资人，我关注的不仅是商业模式，还有团队执行力、市场潜力等因素。','article','投资分析','项目评估,投资标准',180,22,15,1,NULL,'2026-04-04 21:03:00','2026-04-04 21:03:00',0),(6,2,'11111111111111','111111111111','article','创业经验','',0,0,0,1,NULL,NULL,NULL,0),(7,2,'11111111111111','111111111111','article','创业经验','',0,0,0,1,NULL,NULL,NULL,0),(8,2,'pppppppppp','ppppppppppppppppp','article','求职招聘','ppp',0,0,0,1,NULL,NULL,NULL,0),(9,2,'pppppppppp','ppppppppppppppppp','article','求职招聘','ppp',0,0,0,1,NULL,NULL,NULL,0),(10,2,'111111111111','111111111111','article','创业经验','1111111111111111111111',0,0,0,1,NULL,NULL,NULL,0),(11,2,'11111111111111','11111111111111111111','article','融资技巧','111111',0,0,0,1,NULL,NULL,NULL,0),(12,2,'测试帖子','11111111111111111111','article','融资技巧','11111111111111',0,0,0,1,NULL,NULL,NULL,0),(13,2,'测试帖子','11111111111111111111','article','融资技巧','11111111111111',0,0,0,1,NULL,NULL,NULL,0),(14,2,'测试帖子','11111111111111111111','article','融资技巧','11111111111111',0,0,0,1,NULL,NULL,NULL,0),(15,2,'11111111111111','22222222222222222222222222222<img src=\"/static/images/2_1775373363540_d1c05fee.png\" alt=\"图片\" style=\"max-width: 100%; height: auto; margin: 10px 0;\">','article','行业动态','222222222222',3,0,0,1,NULL,NULL,NULL,1),(16,2,'阿达哒哒哒','              啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊<img src=\"/api/static/images/2_1775373536333_876052f6.png\" alt=\"图片\" style=\"max-width: 100